import{_ as e,o as n,c as i,a2 as r}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Patrones y antipatrones","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pipelines/06-patrones-y-antipatrones.md","filePath":"data-engineering/pipelines/06-patrones-y-antipatrones.md","lastUpdated":1782521464000}'),t={name:"data-engineering/pipelines/06-patrones-y-antipatrones.md"};function o(s,a,l,p,d,c){return n(),i("div",null,[...a[0]||(a[0]=[r(`<h1 id="patrones-y-antipatrones" tabindex="-1">Patrones y antipatrones <a class="header-anchor" href="#patrones-y-antipatrones" aria-label="Permalink to &quot;Patrones y antipatrones&quot;">​</a></h1><p>Los mismos problemas aparecen en muchos pipelines. Reconocer patrones ayuda a disenar soluciones mas estables.</p><h2 id="patron-raw-primero" tabindex="-1">Patron: raw primero <a class="header-anchor" href="#patron-raw-primero" aria-label="Permalink to &quot;Patron: raw primero&quot;">​</a></h2><p>Guarda una copia cruda antes de transformar.</p><p>Ventajas:</p><ul><li>Permite reprocesar.</li><li>Facilita auditoria.</li><li>Protege frente a bugs de transformacion.</li><li>Ayuda a depurar cambios en la fuente.</li></ul><h2 id="patron-carga-incremental-con-watermark" tabindex="-1">Patron: carga incremental con watermark <a class="header-anchor" href="#patron-carga-incremental-con-watermark" aria-label="Permalink to &quot;Patron: carga incremental con watermark&quot;">​</a></h2><p>Procesa solo registros nuevos o modificados.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>leer updated_at &gt; ultimo_watermark</span></span>
<span class="line"><span>validar datos</span></span>
<span class="line"><span>escribir destino</span></span>
<span class="line"><span>guardar nuevo watermark</span></span></code></pre></div><p>Guarda el watermark al final, cuando la escritura se haya completado.</p><h2 id="patron-dead-letter-o-cuarentena" tabindex="-1">Patron: dead letter o cuarentena <a class="header-anchor" href="#patron-dead-letter-o-cuarentena" aria-label="Permalink to &quot;Patron: dead letter o cuarentena&quot;">​</a></h2><p>Los registros invalidos no bloquean siempre todo el flujo, pero tampoco desaparecen.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>validos -&gt; curated</span></span>
<span class="line"><span>invalidos -&gt; quarantine con motivo de rechazo</span></span></code></pre></div><h2 id="patron-staging-antes-de-publicar" tabindex="-1">Patron: staging antes de publicar <a class="header-anchor" href="#patron-staging-antes-de-publicar" aria-label="Permalink to &quot;Patron: staging antes de publicar&quot;">​</a></h2><p>Escribe en una zona intermedia, valida y luego publica.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>staging_tmp -&gt; validacion -&gt; tabla_final</span></span></code></pre></div><p>Esto reduce el riesgo de exponer datos parciales.</p><h2 id="patron-configuracion-por-entorno" tabindex="-1">Patron: configuracion por entorno <a class="header-anchor" href="#patron-configuracion-por-entorno" aria-label="Permalink to &quot;Patron: configuracion por entorno&quot;">​</a></h2><p>El mismo pipeline debe poder ejecutarse en desarrollo, pruebas y produccion cambiando configuracion, no codigo.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dev: bucket-dev/raw</span></span>
<span class="line"><span>prod: bucket-prod/raw</span></span></code></pre></div><h2 id="antipatron-append-infinito-sin-deduplicar" tabindex="-1">Antipatron: append infinito sin deduplicar <a class="header-anchor" href="#antipatron-append-infinito-sin-deduplicar" aria-label="Permalink to &quot;Antipatron: append infinito sin deduplicar&quot;">​</a></h2><p>Anadir filas siempre parece facil, pero puede duplicar datos en reintentos y reprocesos.</p><p>Soluciones:</p><ul><li>Clave de idempotencia.</li><li><code>merge</code>.</li><li>Reemplazo por particion.</li><li>Registro de lotes procesados.</li></ul><h2 id="antipatron-transformar-sin-guardar-entrada" tabindex="-1">Antipatron: transformar sin guardar entrada <a class="header-anchor" href="#antipatron-transformar-sin-guardar-entrada" aria-label="Permalink to &quot;Antipatron: transformar sin guardar entrada&quot;">​</a></h2><p>Si solo guardas el resultado final, cualquier bug obliga a volver a pedir datos a la fuente. A veces esa fuente ya no puede entregar el historico.</p><h2 id="antipatron-logica-de-negocio-dispersa" tabindex="-1">Antipatron: logica de negocio dispersa <a class="header-anchor" href="#antipatron-logica-de-negocio-dispersa" aria-label="Permalink to &quot;Antipatron: logica de negocio dispersa&quot;">​</a></h2><p>Cuando una regla vive en SQL, Python, NiFi, una hoja de calculo y un dashboard, nadie sabe cual es la verdad.</p><p>Centraliza reglas criticas o documenta claramente donde se aplican.</p><h2 id="antipatron-alertas-sin-propietario" tabindex="-1">Antipatron: alertas sin propietario <a class="header-anchor" href="#antipatron-alertas-sin-propietario" aria-label="Permalink to &quot;Antipatron: alertas sin propietario&quot;">​</a></h2><p>Una alerta que nadie atiende se convierte en ruido.</p><p>Cada alerta debe tener:</p><ul><li>Servicio afectado.</li><li>Severidad.</li><li>Equipo responsable.</li><li>Accion esperada.</li><li>Enlace al runbook.</li></ul><h2 id="antipatron-pipelines-invisibles" tabindex="-1">Antipatron: pipelines invisibles <a class="header-anchor" href="#antipatron-pipelines-invisibles" aria-label="Permalink to &quot;Antipatron: pipelines invisibles&quot;">​</a></h2><p>Si no hay metricas ni lineage, el pipeline solo existe mientras alguien recuerda como funciona.</p><p>Documenta al menos:</p><ul><li>Entrada.</li><li>Salida.</li><li>Frecuencia.</li><li>Responsable.</li><li>Dependencias.</li><li>Reproceso.</li><li>Alertas.</li></ul><h2 id="regla-final" tabindex="-1">Regla final <a class="header-anchor" href="#regla-final" aria-label="Permalink to &quot;Regla final&quot;">​</a></h2><p>Construye pipelines como si tuvieras que arreglarlos de madrugada con poca informacion. Esa mentalidad mejora el diseno incluso cuando todo va bien.</p>`,39)])])}const g=e(t,[["render",o]]);export{h as __pageData,g as default};
